DROP TRIGGER IF EXISTS tbiu_sc_lon_m_req_note ON sc_lon_m_req_note CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_lon_m_req_note() RETURNS trigger AS $BODY$
declare
  li_count_membank integer;
  ls_memno sc_lon_m_contract.membership_no%type;
BEGIN
--return ;
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_lon_m_req_note
    where loan_requestment_no = NEW.loan_requestment_no;
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;


  --ไม่มีสิทธิแก้ไขความคิดเห็นของผู้อื่น
  if ( (OLD.entry_id IS NOT NULL AND OLD.entry_id::text <> '') and NEW.entry_id <> OLD.entry_id )  then
    CALL spa_dberror('T61:ไม่มีสิทธิแก้ไขความคิดเห็นของผู้อื่น');
  end if;

  if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id := current_setting('app.login_id', true);end if;
  if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date := statement_timestamp();end if;


RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
